can double_if_even(value: int) -> int {
    if value % 2 == 0 {
        return value * 2;
    } else {
        return value;
    }
}

with entry {
    print(double_if_even(6));
}

can sum_until(limit: int) -> int {
    total: int = 0;
    i: int = 1;
    while i <= limit {
        total += i;
        i += 1;
    }
    return total;
}

with entry {
    print(sum_until(5));
}

node Account {
    has owner: str;
    has balance: int = 0;

    can deposit(amount: int) -> int {
        self.balance += amount;
        return self.balance;
    }
}

with entry {
    acct = Account(owner="Mira", balance=20);
    print(acct.deposit(15));
}

node City {
    has name: str;
}

edge Road {
    has distance: int = 0;
}

can describe_city(city: City) -> str {
    return city.name;
}

with entry {
    home = City(name="Oslo");
    print(describe_city(home));
